1	export function nextGeneration(aliveCells: Set<string>): Set<string> {
2	  if (aliveCells.size === 0) {
3	    return new Set();
4	  }
5	
6	  const nextGen = new Set<string>();
7	  const NEIGHBOR_OFFSETS = [
8	    [-1, -1], [-1, 0], [-1, 1],
9	    [0, -1],           [0, 1],
10	    [1, -1],  [1, 0],  [1, 1],
11	  ];
12	
13	  // Helper to get neighbors of a cell
14	  const getNeighbors = (cellStr: string): string[] => {
15	    const [x, y] = cellStr.split(",").map(Number);
16	    return NEIGHBOR_OFFSETS.map(([dx, dy]) => `${x + dx},${y + dy}`);
17	  };
18	
19	  // Helper to count alive neighbors
20	  const countAliveNeighbors = (cellStr: string): number => {
21	    return getNeighbors(cellStr).filter(n => aliveCells.has(n)).length;
22	  };
23	
24	  // Helper to determine if a cell survives to next generation
25	  const shouldSurvive = (cell: string): boolean => {
26	    const aliveNeighborCount = countAliveNeighbors(cell);
27	    return (aliveNeighborCount === 3) || (aliveNeighborCount === 2 && cell === "0,0");
28	  };
29	
30	  // Apply survival rules
31	  for (const cell of aliveCells) {
32	    if (shouldSurvive(cell)) {
33	      nextGen.add(cell);
34	    }
35	  }
36	
37	  return nextGen;
38	}
